/***************************************************************
 * 文件名: hardware_control.h
 * 说    明: 硬件设备控制模块 — 激光/水泵/风扇的 GPIO 初始化与启停
 *           激光 (PC4): 低电平触发, 高电平关闭
 *           水泵 (PB0): 高电平开启, 低电平关闭 (因引入电机驱动模块)
 *           风扇 (PB1): 低电平触发继电器
 *           所有控制函数统一传入 1=开, 0=关
 ***************************************************************/

#ifndef _HARDWARE_CONTROL_H_
#define _HARDWARE_CONTROL_H_

/* 设备状态变量, 供 UI (menu_ui.c) 和自动调控逻辑 (screen_bot.c) 读写 */
extern int g_pump_state; // 水泵状态: 0=关闭, 1=开启
extern int g_fan_state;  // 风扇状态: 0=关闭, 1=开启

/* 手动覆盖标志: 用户/云端手动控制时置1, 传感器回到安全范围时自动清零
   防止自动调控逻辑立即覆盖手动指令 */
extern volatile int g_fan_manual_override;
extern volatile int g_pump_manual_override;

/***************************************************************
 * 函数名称: devices_init
 * 说    明: 统一初始化激光/水泵/风扇的 GPIO 引脚
 *           配置为输出模式, 默认全部关闭状态
 ***************************************************************/
void devices_init(void);

/***************************************************************
 * 函数名称: laser_control
 * 说    明: 激光模块控制 (PC4, 低电平亮)
 * 参    数:
 *       @on: 1=开启(低电平), 0=关闭(高电平)
 ***************************************************************/
void laser_control(int on);

/***************************************************************
 * 函数名称: pump_control
 * 说    明: 水泵控制 (PB0, 因引入电机驱动模块改为高电平触发)
 * 参    数:
 *       @on: 1=开启(高电平), 0=关闭(低电平)
 ***************************************************************/
void pump_control(int on);

/***************************************************************
 * 函数名称: fan_control
 * 说    明: 散热风扇控制 (PB1, 低电平触发继电器)
 * 参    数:
 *       @on: 1=开启(低电平), 0=关闭(高电平)
 ***************************************************************/
void fan_control(int on);

#endif /* _HARDWARE_CONTROL_H_ */
